class Solution:
    def countVowelStrings(self, n):
        dp = [1, 1, 1, 1, 1]
        for _ in range(n - 1):
            new = [0, 0, 0, 0, 0]
            running = 0
            for i in range(5):
                running += dp[i]
                new[i] = running
            dp = new
        return sum(dp)

