var countVowelStrings = function(n) {
    let dp = [1, 1, 1, 1, 1];
    for (let step = 1; step < n; step++) {
        const next = [0, 0, 0, 0, 0];
        let running = 0;
        for (let i = 0; i < 5; i++) {
            running += dp[i];
            next[i] = running;
        }
        dp = next;
    }
    return dp.reduce((a, b) => a + b, 0);
};
